const softDeleteChatMessage = `-- name: SoftDeleteChatMessage :exec
UPDATE chat_messages
SET deleted_at = $3
WHERE id = $1 AND user_id = $2 AND deleted_at IS NULL
`

type SoftDeleteChatMessageParams struct {
	ID        int64
	UserID    int64
	DeletedAt pgtype.Timestamptz
}

// Author-only delete. The user_id guard refuses someone else's row even if
// the caller passes a stale id; sysop deletes go through the sysop variant.
func (q *Queries) SoftDeleteChatMessage(ctx context.Context, arg SoftDeleteChatMessageParams) error {
	_, err := q.db.Exec(ctx, softDeleteChatMessage, arg.ID, arg.UserID, arg.DeletedAt)
	return err
}

